"use client";

/* ════════════════════════════════════════════════════════════════════════
   <PagePerfScatter> — rank × revenue bubble scatter for Growth · Pages.

   Question it answers: which pages punch above their rank?
   Tier-2 per CHART-STANDARD §5.1.  Money-zone callout reveals the
   honest-truth that top-left bubbles convert traffic to dollars best;
   blog pages in the bottom-left are "rank without revenue" traps.

   §2 compliance: real-px viewBox via useChartSize, ChartStates wrapper,
   typed data with exported sampleData, reduced-motion respected.
   ──────────────────────────────────────────────────────────────────────── */

import { useEffect, useState } from "react";
import { useChartSize, usePrefersReducedMotion } from "@/lib/useChartSize";
import { ChartStates, type ChartState } from "./_kit/ChartStates";

export type PagePerfCategory = "Bouquets" | "Products" | "Wedding" | "Blog" | "Landing";

export interface PagePerfPoint {
  name: string;
  /** Average SERP rank (1+). Lower = better. */
  rank: number;
  /** Monthly revenue in $K. */
  rev: number;
  category: PagePerfCategory;
}

export interface PagePerfScatterProps {
  data?: PagePerfPoint[];
  /** Color per category. Defaults to canonical category palette. */
  colorMap?: Record<PagePerfCategory, string>;
  state?: ChartState;
  label?: string;
  /** Click handler if you want bubbles to deep-link to the page detail. */
  onPointClick?: (i: number, p: PagePerfPoint) => void;
}

export const DEFAULT_PAGE_PERF_COLORS: Record<PagePerfCategory, string> = {
  Bouquets: "#7F77DD",
  Products: "#1D9E75",
  Wedding: "#D4537E",
  Blog: "#5B7CB0",
  Landing: "#E8932D",
};

export const samplePagePerfData: PagePerfPoint[] = [
  { name: "Best Selling Flowers", rank: 4.2, rev: 89, category: "Bouquets" },
  { name: "Premium Bouquets", rank: 3.8, rev: 67, category: "Bouquets" },
  { name: "Rose Bouquets", rank: 2.1, rev: 52, category: "Bouquets" },
  { name: "Red Rose Luxury Box", rank: 5.4, rev: 48, category: "Products" },
  { name: "Valentine's Day", rank: 4.6, rev: 42, category: "Wedding" },
  { name: "Wedding Flowers", rank: 8.2, rev: 39, category: "Wedding" },
  { name: "Subscription Box", rank: 9.8, rev: 32, category: "Products" },
  { name: "Same Day Delivery", rank: 5.2, rev: 29, category: "Landing" },
  { name: "Orchid Arrangements", rank: 4.6, rev: 28, category: "Bouquets" },
  { name: "Bridal Bouquets", rank: 10.4, rev: 28, category: "Wedding" },
  { name: "Deluxe Gift Hamper", rank: 8.2, rev: 26, category: "Products" },
  { name: "Orchid Cascade", rank: 8.6, rev: 25, category: "Products" },
  { name: "Carnation Box", rank: 6.0, rev: 22, category: "Products" },
  { name: "Sympathy Flowers", rank: 7.5, rev: 19, category: "Wedding" },
  { name: "Tulip Bouquet", rank: 11.2, rev: 16, category: "Bouquets" },
  { name: "Lily Arrangement", rank: 12.8, rev: 14, category: "Bouquets" },
  { name: "Hydrangea", rank: 13.5, rev: 11, category: "Products" },
  { name: "Flower Care Guide", rank: 2.0, rev: 9, category: "Blog" },
  { name: "Gift Card", rank: 16.0, rev: 7, category: "Landing" },
  { name: "Preserved Flowers", rank: 17.2, rev: 5, category: "Blog" },
];

export function PagePerfScatter({
  data = samplePagePerfData,
  colorMap = DEFAULT_PAGE_PERF_COLORS,
  state = "ready",
  label = "Page performance",
  onPointClick,
}: PagePerfScatterProps) {
  const { ref, width } = useChartSize({ min: 720, fallback: 1000 });
  const reduce = usePrefersReducedMotion();
  const [popped, setPopped] = useState(false);

  const W = Math.max(720, width);
  const H = 372;
  const padL = 14;
  const padR = 14;
  const padT = 26;
  const padB = 74;
  const plotL = padL;
  const plotR = W - padR;
  const plotT = padT;
  const plotB = H - padB;

  const X = (rank: number) => plotL + ((rank - 1) / 17) * (plotR - plotL);
  const Y = (rev: number) => plotB - (rev / 100) * (plotB - plotT);
  const RAD = (rev: number) => Math.max(5, Math.sqrt(rev) * 2.05);

  const yTicks = [0, 25, 50, 75, 100];
  const xTicks = [2, 4, 6, 8, 12, 18];

  // One-shot pop-in for the bubbles
  useEffect(() => {
    if (reduce) {
      setPopped(true);
      return;
    }
    const r = requestAnimationFrame(() => requestAnimationFrame(() => setPopped(true)));
    return () => cancelAnimationFrame(r);
  }, [reduce]);

  // Sort big-to-small so small bubbles sit on top
  const ordered = [...data]
    .map((p, idx) => ({ p, idx }))
    .sort((a, b) => b.p.rev - a.p.rev);

  return (
    <div ref={ref}>
      <ChartStates state={state} height={H} label={label}>
        <svg className="page-perf-svg" viewBox={`0 0 ${W} ${H}`} style={{ width: "100%", height: H, display: "block" }}>
          {/* Money zone — top-left rectangle (rank ≤ 5, rev ≥ 46) */}
          <rect
            x={plotL}
            y={plotT}
            width={X(5) - plotL}
            height={Y(46) - plotT}
            rx={6}
            fill="rgba(29,158,117,0.045)"
            stroke="rgba(29,158,117,0.20)"
            strokeWidth={0.8}
            strokeDasharray="4 4"
          />
          <text
            x={plotL + 10}
            y={plotT + 18}
            fontFamily="JetBrains Mono, monospace"
            fontSize={10}
            fontWeight={600}
            letterSpacing="0.10em"
            fill="rgba(29,158,117,0.82)"
          >
            MONEY PAGES
          </text>

          {/* Y gridlines + axis labels */}
          {yTicks.map((v) => {
            const yy = Y(v);
            return (
              <g key={`y-${v}`}>
                <line
                  x1={plotL}
                  y1={yy}
                  x2={plotR}
                  y2={yy}
                  stroke="rgba(0,0,0,0.05)"
                  strokeWidth={1}
                />
                <text
                  x={plotL + 5}
                  y={yy - 7}
                  fontFamily="JetBrains Mono, monospace"
                  fontSize={11}
                  fontWeight={500}
                  fill="var(--ink-2)"
                  letterSpacing="0.02em"
                  paintOrder="stroke"
                  stroke="#f3f1eb"
                  strokeWidth={3.5}
                  strokeLinejoin="round"
                >
                  {v === 0 ? "$0" : `$${v}K`}
                </text>
              </g>
            );
          })}

          {/* Bubbles */}
          {ordered.map(({ p, idx }, k) => {
            const cx = X(p.rank);
            const cy = Y(p.rev);
            const r = RAD(p.rev);
            const fill = colorMap[p.category];
            return (
              <g
                key={p.name}
                style={{
                  opacity: popped ? 1 : 0,
                  transform: popped ? "scale(1)" : "scale(0.4)",
                  transformOrigin: `${cx}px ${cy}px`,
                  transformBox: "fill-box",
                  transition: `opacity 0.4s ${0.04 + k * 0.025}s, transform 0.55s cubic-bezier(.4,.1,.2,1) ${0.04 + k * 0.025}s`,
                }}
              >
                <circle
                  cx={cx}
                  cy={cy}
                  r={r}
                  fill={fill}
                  fillOpacity={0.82}
                  stroke="#fff"
                  strokeWidth={1.5}
                  style={onPointClick ? { cursor: "pointer" } : undefined}
                  onClick={() => onPointClick?.(idx, p)}
                />
              </g>
            );
          })}

          {/* X axis position ticks */}
          {xTicks.map((p) => (
            <text
              key={`xt-${p}`}
              x={X(p)}
              y={plotB + 22}
              fontFamily="JetBrains Mono, monospace"
              fontSize={11}
              fill="var(--ink-2)"
              textAnchor="middle"
              letterSpacing="0.02em"
            >
              #{p}
            </text>
          ))}
          <text
            x={(plotL + plotR) / 2}
            y={plotB + 44}
            fontFamily="JetBrains Mono, monospace"
            fontSize={11}
            fontWeight={600}
            fill="var(--ink-2)"
            textAnchor="middle"
            letterSpacing="0.02em"
          >
            POSITION →
          </text>
        </svg>
      </ChartStates>
    </div>
  );
}
