/**
 * Mock data for Growth · Pages.
 *
 * One row per indexed page, plus the monthly rev-vs-traffic correlation
 * series and the rank-vs-revenue scatter. USD currency (per canonical rule).
 */

export type PageIntent = "Commercial" | "Transactional" | "Informational";
export type PageValueTier = "high" | "mid" | "low";
export type PageChange = "up" | "down" | "flat";
export type PageCategory = "Bouquets" | "Products" | "Wedding" | "Blog" | "Landing";

export interface PageRow {
  id: string;
  name: string;
  url: string;
  intent: PageIntent;
  /** Monthly organic visits, e.g. "4.2K" */
  traffic: string;
  /** Monthly revenue, USD */
  revenue: string;
  /** Revenue / visit. */
  value: string;
  valueTier: PageValueTier;
  /** "strong" / "ok" / "vanity" — the qualitative label. */
  valueTag: string;
  /** Avg SERP position e.g. "#4.2" */
  position: string;
  /** Period-over-period change. */
  change: string;
  changeDir: PageChange;
  category: PageCategory;
}

