"use client";

import { useMemo, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { SectionLabel } from "@/components/shared/SectionLabel";
import { OrganicRevenueTraffic } from "@/components/charts/OrganicRevenueTraffic";
import { PagePerfScatter } from "@/components/charts/PagePerfScatter";
import { useBridge } from "@/features/bridge/hooks/use-bridge";
import {
  PAGES,
  PAGES_TREND,
  pagesTrendAnnotations,
  SCATTER,
  CATEGORY_COLOR,
  categories,
  concentration,
  pagesMetrics,
  pagesAI,
  type PageRow,
} from "@/features/growth/api/growth-pages-data";
import "./pages.css";

const PERIOD_LABELS = ["7 days", "30 days", "90 days"];
const DEVICE_LABELS = ["All", "Desktop", "Mobile"];

type TableKey = "name" | "intent" | "traffic" | "rev" | "value" | "pos" | "change";
const num = (s: string) => {
  if (!s || s === "—") return 0;
  const m = s.replace(/[,$#%↑↓]/g, "").match(/-?\d+(?:\.\d+)?/);
  if (!m) return 0;
  let v = parseFloat(m[0]);
  if (/k/i.test(s)) v *= 1000;
  return v;
};

export default function PagesPage() {
  const [periodIdx, setPeriodIdx] = useState(1);
  const [deviceIdx, setDeviceIdx] = useState(0);
  const [sortKey, setSortKey] = useState<TableKey>("rev");
  const [sortDir, setSortDir] = useState<1 | -1>(-1);
  const [search, setSearch] = useState("");
  const { openBridge } = useBridge();

  const tableRows = useMemo(() => {
    const q = search.toLowerCase().trim();
    const arr = PAGES.filter((p) =>
      q
        ? p.name.toLowerCase().includes(q) || p.url.toLowerCase().includes(q)
        : true,
    );
    arr.sort((a, b) => {
      if (sortKey === "name") return sortDir * a.name.localeCompare(b.name);
      if (sortKey === "intent") return sortDir * a.intent.localeCompare(b.intent);
      if (sortKey === "traffic") return sortDir * (num(a.traffic) - num(b.traffic));
      if (sortKey === "rev") return sortDir * (num(a.revenue) - num(b.revenue));
      if (sortKey === "value") return sortDir * (num(a.value) - num(b.value));
      if (sortKey === "pos") return sortDir * (num(a.position) - num(b.position));
      if (sortKey === "change") {
        const av = a.changeDir === "up" ? num(a.change) : a.changeDir === "down" ? -num(a.change) : 0;
        const bv = b.changeDir === "up" ? num(b.change) : b.changeDir === "down" ? -num(b.change) : 0;
        return sortDir * (av - bv);
      }
      return 0;
    });
    return arr;
  }, [sortKey, sortDir, search]);
  const onSort = (k: TableKey) => {
    if (sortKey === k) setSortDir((d) => (d === 1 ? -1 : 1));
    else {
      setSortKey(k);
      setSortDir(k === "name" || k === "intent" ? 1 : -1);
    }
  };

  return (
    <div className="growth-pages-page">
      <DeptHeader
        dept="growth"
        title="Pages"
        meta={
          <>
            <span className="live">Live</span> · Revenue by page · from Search Console + orders
          </>
        }
        actions={
          <>
            <button className="btn-util">Export</button>
            <button
              className="btn-util primary"
              type="button"
              onClick={() => openBridge("growth")}
            >
              Fix content gaps →
            </button>
          </>
        }
      />

      <div className="toggle-row">
        <PeriodTabs labels={PERIOD_LABELS} activeIndex={periodIdx} onChange={setPeriodIdx} marginBottom={0} accent="var(--d-growth)" showRange={false} />
        <PeriodTabs labels={DEVICE_LABELS} activeIndex={deviceIdx} onChange={setDeviceIdx} marginBottom={0} accent="var(--d-growth)" />
      </div>

      <div className="metric-strip">
        <div className="metric">
          <div className="metric-l">Organic Revenue</div>
          <div className="metric-v green">{pagesMetrics.revenue}</div>
          <div className="metric-s">{pagesMetrics.revenueSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Organic Traffic</div>
          <div className="metric-v">{pagesMetrics.traffic}</div>
          <div className="metric-s">{pagesMetrics.trafficSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Conversion Rate</div>
          <div className="metric-v">{pagesMetrics.conversionRate}</div>
          <div className="metric-s">{pagesMetrics.conversionSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Avg Order Value</div>
          <div className="metric-v">{pagesMetrics.aov}</div>
          <div className="metric-s">{pagesMetrics.aovSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Traffic Value</div>
          <div className="metric-v">{pagesMetrics.trafficValue}</div>
          <div className="metric-s">{pagesMetrics.trafficValueSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Pages Indexed</div>
          <div className="metric-v">{pagesMetrics.pagesIndexed}</div>
          <div className="metric-s">{pagesMetrics.pagesIndexedSub}</div>
        </div>
      </div>

      <AIStrip label={pagesAI.label} meta={pagesAI.meta} cards={pagesAI.cards} />

      {/* Trend chart */}
      <SectionLabel>Organic revenue &amp; traffic · monthly</SectionLabel>
      <div className="inst-card" style={{ marginBottom: 18 }}>
        <div className="inst-head">
          <div>
            <span className="inst-title">Revenue vs. traffic — do they move together?</span>
            <div className="tc-hero">
              <span className="big">$160K</span>
              <span className="d">↑ from $42K · 12 mo</span>
            </div>
            <div
              style={{
                fontFamily: "var(--font-mono)",
                fontSize: 10,
                color: "var(--ink-3)",
                marginTop: 6,
                letterSpacing: "0.02em",
              }}
            >
              Left axis = visits · right axis = revenue · when revenue outpaces traffic, you&rsquo;re converting better
            </div>
          </div>
          <div style={{ display: "flex", flexDirection: "column", alignItems: "flex-end", gap: 9 }}>
            <div className="tc-live">
              <span className="dot" />Live · GSC + orders
            </div>
            <div className="inst-legend">
              <span><span className="sw sw-sq" style={{ background: "var(--d-finance)" }} />Revenue</span>
              <span><span className="sw sw-sq" style={{ background: "var(--d-growth)" }} />Traffic</span>
            </div>
          </div>
        </div>
        <OrganicRevenueTraffic data={PAGES_TREND} annotations={pagesTrendAnnotations} />
        <div className="driver-callout">
          <span className="driver-tag">The correlation</span>
          <span className="driver-text">
            Traffic grew <b>+233%</b>, but revenue grew <b>+281%</b> — revenue is outpacing traffic, which means each visit is worth more than it was a year ago. You&rsquo;re not just getting more visitors, you&rsquo;re <b>converting them better</b>. The Oct pages and Valentine peak lifted both together.
          </span>
        </div>
      </div>

      {/* Performance scatter */}
      <SectionLabel>Performance map · rank ≠ revenue</SectionLabel>
      <div className="inst-card scatter-card">
        <div className="inst-head">
          <span className="inst-title">Position vs. Revenue</span>
          <div className="inst-legend">
            {Object.entries(CATEGORY_COLOR).map(([name, color]) => (
              <span key={name}>
                <span className="sw" style={{ background: color }} />
                {name}
              </span>
            ))}
          </div>
        </div>
        <PagePerfScatter data={SCATTER} colorMap={CATEGORY_COLOR} />
      </div>

      {/* Concentration */}
      <div className="conc-card">
        <div className="conc-head">
          <span className="conc-title">Revenue concentration</span>
          <span className="conc-state">{concentration.state}</span>
        </div>
        <div className="conc-big">{concentration.pct}%</div>
        <div className="conc-cap">{concentration.cap}</div>
        <div className="conc-rows">
          {concentration.rows.map((r) => (
            <div key={r.name} className={`conc-row${r.rest ? " rest" : ""}`}>
              <span className="cr-name">
                <span className="cd" style={{ background: r.color }} />
                {r.name}
              </span>
              <span className="cr-bar">
                <span
                  className="cr-fill"
                  style={{ width: `${r.bar}%`, background: r.color }}
                />
              </span>
              <span className="cr-pct">{r.pct}%</span>
            </div>
          ))}
        </div>
        <div className="conc-note" dangerouslySetInnerHTML={{ __html: concentration.note.replace(/(\$\d+K\/month)/, "<b>$1</b>") }} />
      </div>

      {/* Category grid */}
      <SectionLabel>Revenue by category</SectionLabel>
      <div className="cat-grid">
        {categories.map((c) => (
          <div
            key={c.id}
            className="cat-card"
            style={{
              ["--cat-c" as string]: CATEGORY_COLOR[c.id],
              ["--cat-tint" as string]: c.tint,
            } as React.CSSProperties}
          >
            <div className="cat-name">
              <span className="cdot" />
              {c.name}
            </div>
            <div className="cat-val">{c.revenue}</div>
            <div className="cat-sub">
              {c.pages} pages · {c.pct}%
            </div>
          </div>
        ))}
      </div>

      {/* All pages table */}
      <SectionLabel>All pages</SectionLabel>
      <div className="pages-table">
        <div className="pt-tools">
          <div className="pt-search">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
              <circle cx="11" cy="11" r="8" />
              <line x1="21" y1="21" x2="16.65" y2="16.65" />
            </svg>
            <input
              type="text"
              placeholder="Search pages, URLs, or keywords..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </div>
          <button className="pt-pill" type="button">
            All Pages
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <polyline points="6 9 12 15 18 9" />
            </svg>
          </button>
          <button className="pt-pill" type="button">
            All Intents
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <polyline points="6 9 12 15 18 9" />
            </svg>
          </button>
        </div>

        <div className="pt-cols">
          <PtCol k="name" active={sortKey === "name"} dir={sortDir} onSort={onSort}>Page</PtCol>
          <PtCol k="intent" active={sortKey === "intent"} dir={sortDir} onSort={onSort}>Intent</PtCol>
          <PtCol k="traffic" active={sortKey === "traffic"} dir={sortDir} onSort={onSort} right>Traffic</PtCol>
          <PtCol k="rev" active={sortKey === "rev"} dir={sortDir} onSort={onSort} right>Revenue</PtCol>
          <PtCol k="value" active={sortKey === "value"} dir={sortDir} onSort={onSort} right>Value</PtCol>
          <PtCol k="pos" active={sortKey === "pos"} dir={sortDir} onSort={onSort} right>Position</PtCol>
          <PtCol k="change" active={sortKey === "change"} dir={sortDir} onSort={onSort} right>Change</PtCol>
        </div>
        {tableRows.map((p) => <PtRow key={p.id} p={p} />)}
      </div>
    </div>
  );
}

interface PtColProps {
  k: TableKey;
  active: boolean;
  dir: 1 | -1;
  onSort: (k: TableKey) => void;
  right?: boolean;
  children: React.ReactNode;
}
function PtCol({ k, active, dir, onSort, right, children }: PtColProps) {
  return (
    <span
      className={`c${right ? " r" : ""}${active ? " active" : ""}`}
      onClick={() => onSort(k)}
    >
      {children}
      <span className="sort-ar">{active && dir < 0 ? "↓" : "↑"}</span>
    </span>
  );
}

function PtRow({ p }: { p: PageRow }) {
  return (
    <div className="pt-row">
      <div className="pt-page">
        <div className="pt-name">{p.name}</div>
        <div className="pt-url">{p.url}</div>
      </div>
      <div className="pt-intent">
        <span
          className={`pt-tag ${p.intent === "Commercial" ? "comm" : p.intent === "Transactional" ? "trans" : "info2"}`}
        >
          {p.intent}
        </span>
      </div>
      <div className="pt-num muted">{p.traffic}</div>
      <div className="pt-num rev">{p.revenue}</div>
      <div className={`pt-value ${p.valueTier}`}>
        <span className="vv">{p.value}</span>
        <span className="vt">{p.valueTag}</span>
      </div>
      <div className="pt-pos">{p.position}</div>
      <div className={`pt-change ${p.changeDir}`}>{p.change}</div>
    </div>
  );
}

