"use client";

/* ════════════════════════════════════════════════════════════════════════
   <OrganicRevenueTraffic> — Tier-2 monthly trend per CHART-STANDARD §5.1.

   Question it answers: are revenue and traffic moving together?
   Two lines, dual-axis (visits left / revenue right). The pulsing
   now-beacon and reading-window mark the latest revenue point so the
   story reads even before the eye walks the line.

   §2 compliance:
   - viewBox === real px width via useChartSize
   - Typed data via OrganicTrendPoint[]
   - Routes through <ChartStates> (loading / empty / partial / error)
   - Reduced motion → draw-in completes instantly, no beacon pulse
   ──────────────────────────────────────────────────────────────────────── */

import { useEffect, useRef, useState } from "react";
import { useChartSize, usePrefersReducedMotion } from "@/lib/useChartSize";
import { ChartStates, type ChartState } from "./_kit/ChartStates";

export interface OrganicTrendPoint {
  /** Short month label e.g. "Jun". */
  month: string;
  /** Revenue, $K. */
  rev: number;
  /** Traffic, K visits. */
  traf: number;
}

export interface OrganicTrendAnnotation {
  /** Index into the data series this annotation pins to. */
  idx: number;
  label: string;
}

export interface OrganicRevenueTrafficProps {
  data?: OrganicTrendPoint[];
  annotations?: OrganicTrendAnnotation[];
  /** Max revenue for the right-axis scale ($K). Defaults derived. */
  yMaxRev?: number;
  /** Max traffic for the left-axis scale (K visits). Defaults derived. */
  yMaxTraf?: number;
  state?: ChartState;
  label?: string;
}

export const sampleOrganicTrendData: OrganicTrendPoint[] = [
  { month: "Jun", rev: 42, traf: 2.1 },
  { month: "Jul", rev: 46, traf: 2.3 },
  { month: "Aug", rev: 52, traf: 2.6 },
  { month: "Sep", rev: 58, traf: 2.9 },
  { month: "Oct", rev: 66, traf: 3.3 },
  { month: "Nov", rev: 70, traf: 3.8 },
  { month: "Dec", rev: 72, traf: 3.6 },
  { month: "Jan", rev: 86, traf: 4.6 },
  { month: "Feb", rev: 102, traf: 5.0 },
  { month: "Mar", rev: 120, traf: 5.8 },
  { month: "Apr", rev: 140, traf: 6.4 },
  { month: "May", rev: 160, traf: 7.0 },
];
export const sampleOrganicTrendAnnotations: OrganicTrendAnnotation[] = [
  { idx: 4, label: "Oct · 4 new pages" },
  { idx: 8, label: "Feb · Valentine" },
];

export function OrganicRevenueTraffic({
  data = sampleOrganicTrendData,
  annotations = sampleOrganicTrendAnnotations,
  yMaxRev,
  yMaxTraf,
  state = "ready",
  label = "Revenue vs traffic",
}: OrganicRevenueTrafficProps) {
  const { ref, width } = useChartSize({ min: 720, fallback: 1000 });
  const reduce = usePrefersReducedMotion();
  const [drawn, setDrawn] = useState(false);
  // Track each polyline so we can set strokeDasharray/offset for the draw-in
  const revLineRef = useRef<SVGPolylineElement | null>(null);
  const trafLineRef = useRef<SVGPolylineElement | null>(null);

  const W = Math.max(720, width);
  const H = 300;
  const padL = 12;
  const padR = 12;
  const padT = 34;
  const padB = 50;
  const plotL = padL;
  const plotR = W - padR;
  const plotT = padT;
  const plotB = H - padB;
  const n = data.length;

  const maxRev = yMaxRev ?? Math.max(170, Math.ceil(Math.max(...data.map((d) => d.rev)) / 50) * 50);
  const maxTraf =
    yMaxTraf ?? Math.max(7.5, Math.ceil(Math.max(...data.map((d) => d.traf)) * 1.05 * 2) / 2);

  const X = (i: number) => plotL + (i / Math.max(1, n - 1)) * (plotR - plotL);
  const yRev = (v: number) => plotB - (v / maxRev) * (plotB - plotT);
  const yTraf = (v: number) => plotB - (v / maxTraf) * (plotB - plotT);
  const gy = (k: number) => plotB - ((plotB - plotT) * k) / 3;

  const revPath = data.map((p, i) => `${X(i).toFixed(1)},${yRev(p.rev).toFixed(1)}`).join(" ");
  const trafPath = data.map((p, i) => `${X(i).toFixed(1)},${yTraf(p.traf).toFixed(1)}`).join(" ");
  const area =
    data.map((p, i) => `${X(i).toFixed(1)},${yRev(p.rev).toFixed(1)}`).join(" ") +
    ` ${X(n - 1).toFixed(1)},${plotB} ${X(0).toFixed(1)},${plotB}`;

  const trafLabels = [
    "0",
    `${(maxTraf / 3).toFixed(1)}K`,
    `${((maxTraf / 3) * 2).toFixed(1)}K`,
    `${maxTraf.toFixed(1)}K`,
  ];
  const revLabels = [
    "$0",
    `$${Math.round(maxRev / 3)}K`,
    `$${Math.round((maxRev / 3) * 2)}K`,
    `$${Math.round(maxRev)}K`,
  ];

  // One-shot draw-in animation, fires on mount only (not on resize).
  useEffect(() => {
    if (reduce) {
      setDrawn(true);
      return;
    }
    const r = requestAnimationFrame(() => requestAnimationFrame(() => setDrawn(true)));
    return () => cancelAnimationFrame(r);
  }, [reduce]);

  // Recompute path lengths whenever dimensions change so the dash math stays right
  const lineLen = (plotR - plotL) + 80;

  const lastRev = data[n - 1];
  const nx = X(n - 1);
  const ny = yRev(lastRev.rev);
  const nyFmt = `$${lastRev.rev}K`;

  return (
    <div ref={ref}>
      <ChartStates state={state} height={H} label={label}>
        <svg className="orgtrend-svg" viewBox={`0 0 ${W} ${H}`} style={{ width: "100%", height: H, display: "block" }}>
          <defs>
            <linearGradient id="orgtrend-grad" x1="0" y1="0" x2="0" y2="1">
              <stop offset="0" stopColor="#1D9E75" stopOpacity="0.18" />
              <stop offset="1" stopColor="#1D9E75" stopOpacity="0.02" />
            </linearGradient>
          </defs>

          {[0, 1, 2, 3].map((k) => {
            const yy = gy(k);
            return (
              <g key={`gr-${k}`}>
                <line
                  x1={plotL}
                  y1={yy}
                  x2={plotR}
                  y2={yy}
                  stroke="rgba(0,0,0,0.05)"
                  strokeWidth={1}
                />
                <text
                  x={plotL + 5}
                  y={yy - 7}
                  fontFamily="JetBrains Mono, monospace"
                  fontSize={11}
                  fontWeight={500}
                  fill="var(--ink-2)"
                  letterSpacing="0.02em"
                >
                  {trafLabels[k]}
                </text>
                <text
                  x={plotR - 5}
                  y={yy - 7}
                  fontFamily="JetBrains Mono, monospace"
                  fontSize={11}
                  fontWeight={500}
                  fill="var(--ink-2)"
                  letterSpacing="0.02em"
                  textAnchor="end"
                >
                  {revLabels[k]}
                </text>
              </g>
            );
          })}

          {/* Gold corner brackets — the whisper framing */}
          {[
            `M${plotL},${plotT + 18} L${plotL},${plotT} L${plotL + 18},${plotT}`,
            `M${plotR - 18},${plotT} L${plotR},${plotT} L${plotR},${plotT + 18}`,
            `M${plotL},${plotB - 18} L${plotL},${plotB} L${plotL + 18},${plotB}`,
            `M${plotR - 18},${plotB} L${plotR},${plotB} L${plotR},${plotB - 18}`,
          ].map((d, i) => (
            <path
              key={`b-${i}`}
              d={d}
              stroke="#b88a2a"
              strokeWidth={1.4}
              fill="none"
              opacity={0.5}
            />
          ))}

          {/* Annotations */}
          {annotations
            .filter((a) => a.idx >= 0 && a.idx < n)
            .map((a, i) => {
              const ax = X(a.idx);
              return (
                <g key={`an-${i}`}>
                  <line
                    x1={ax}
                    y1={plotT}
                    x2={ax}
                    y2={plotB}
                    stroke="rgba(0,0,0,0.12)"
                    strokeWidth={0.8}
                    strokeDasharray="3 3"
                  />
                  <text
                    x={ax + 6}
                    y={plotT + 12}
                    fontFamily="JetBrains Mono, monospace"
                    fontSize={9}
                    fill="var(--ink-3)"
                    letterSpacing="0.04em"
                  >
                    {a.label}
                  </text>
                </g>
              );
            })}

          {/* Revenue area fill (clipped via mask not needed — area path already shaped) */}
          <polygon
            points={area}
            fill="url(#orgtrend-grad)"
            style={{
              opacity: drawn ? 1 : 0,
              transition: "opacity 0.55s ease 0.85s",
            }}
          />

          {/* Two lines — one-shot draw-in via stroke-dash */}
          <polyline
            ref={trafLineRef}
            points={trafPath}
            fill="none"
            stroke="#7F77DD"
            strokeWidth={2}
            strokeLinecap="round"
            strokeLinejoin="round"
            style={{
              strokeDasharray: lineLen,
              strokeDashoffset: drawn ? 0 : lineLen,
              transition: "stroke-dashoffset 1.5s cubic-bezier(.4,.1,.2,1)",
            }}
          />
          <polyline
            ref={revLineRef}
            points={revPath}
            fill="none"
            stroke="#1D9E75"
            strokeWidth={2.6}
            strokeLinecap="round"
            strokeLinejoin="round"
            style={{
              strokeDasharray: lineLen,
              strokeDashoffset: drawn ? 0 : lineLen,
              transition: "stroke-dashoffset 1.5s cubic-bezier(.4,.1,.2,1) 0.15s",
            }}
          />

          {/* Traffic nodes */}
          {data.map((p, i) => (
            <rect
              key={`tn-${i}`}
              x={X(i) - 2.5}
              y={yTraf(p.traf) - 2.5}
              width={5}
              height={5}
              rx={1.5}
              fill="#fff"
              stroke="#7F77DD"
              strokeWidth={1.6}
              style={{ opacity: drawn ? 1 : 0, transition: `opacity 0.18s ${1.45 + i * 0.03}s` }}
            />
          ))}
          {/* Revenue nodes — skip the last so the now-pin owns it */}
          {data.slice(0, -1).map((p, i) => (
            <rect
              key={`rn-${i}`}
              x={X(i) - 3.5}
              y={yRev(p.rev) - 3.5}
              width={7}
              height={7}
              rx={1.5}
              fill="#fff"
              stroke="#1D9E75"
              strokeWidth={1.6}
              style={{ opacity: drawn ? 1 : 0, transition: `opacity 0.18s ${1.5 + i * 0.03}s` }}
            />
          ))}

          {/* Now-pin: drop line, pulsing beacon, square node, reading window */}
          <g style={{ opacity: drawn ? 1 : 0, transition: "opacity 0.35s 1.9s" }}>
            <line
              x1={nx}
              y1={ny}
              x2={nx}
              y2={plotB}
              stroke="#5B7CB0"
              strokeWidth={1.2}
              strokeDasharray="2 3"
              opacity={0.6}
            />
            {!reduce && (
              <>
                <circle cx={nx} cy={ny} r={6} fill="none" stroke="#5B7CB0" strokeWidth={1.8}>
                  <animate attributeName="r" values="6;20" dur="2.2s" repeatCount="indefinite" />
                  <animate attributeName="opacity" values="0.55;0" dur="2.2s" repeatCount="indefinite" />
                </circle>
                <circle cx={nx} cy={ny} r={6} fill="none" stroke="#5B7CB0" strokeWidth={1.8}>
                  <animate attributeName="r" values="6;20" begin="1.1s" dur="2.2s" repeatCount="indefinite" />
                  <animate attributeName="opacity" values="0.55;0" begin="1.1s" dur="2.2s" repeatCount="indefinite" />
                </circle>
              </>
            )}
            <rect
              x={nx - 4.5}
              y={ny - 4.5}
              width={9}
              height={9}
              rx={1.5}
              fill="#1D9E75"
              stroke="#fff"
              strokeWidth={1.8}
            />
            {/* Reading window */}
            <rect
              x={nx - 92}
              y={ny - 11}
              width={54}
              height={22}
              rx={3}
              fill="#fffdf8"
              stroke="#b88a2a"
              strokeWidth={0.8}
            />
            <rect x={nx - 92} y={ny - 11} width={3} height={22} rx={1} fill="#5B7CB0" />
            <text
              x={nx - 62}
              y={ny + 4}
              fontFamily="Inter, sans-serif"
              fontSize={13}
              fontWeight={600}
              fill="var(--ink)"
              textAnchor="middle"
            >
              {nyFmt}
            </text>
          </g>

          {/* X labels */}
          {data.map((p, i) => {
            const now = i === n - 1;
            return (
              <text
                key={`m-${i}`}
                x={X(i)}
                y={plotB + 24}
                fontFamily="JetBrains Mono, monospace"
                fontSize={11}
                fontWeight={now ? 600 : 500}
                fill={now ? "var(--ink)" : "var(--ink-2)"}
                textAnchor="middle"
              >
                {p.month}
              </text>
            );
          })}
        </svg>
      </ChartStates>
    </div>
  );
}
